+fn wrap_text_cached(base: &Text, width: u16, mode: WrapMode) -> Text {
+    let wrap_width = usize::from(width.max(1));
+    let mut out = Vec::new();
+    for line in base.lines() {
+        if line.width() > wrap_width {
+            out.extend(line.wrap(wrap_width, mode));
+        } else {
+            out.push(line.clone());
+        }
+    }
